using namespace llvm;
using namespace llvm::PatternMatch;

namespace {

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

bool
isDeadIfUnused(const Instruction& I)
{
  if (I.isTerminator())
    return false;
  if (I.mayHaveSideEffects())
    return false;
  if (isa<CallBase>(I))
    return false;
  return true;
}

// ---------------------------------------------------------------------------
// Constant folding
// ---------------------------------------------------------------------------
Constant*
foldBinop(BinaryOperator* bo, ConstantInt* l, ConstantInt* r)
{
  auto ty = bo->getType();
  switch (bo->getOpcode()) {
    case Instruction::Add:
      return ConstantInt::get(ty, l->getSExtValue() + r->getSExtValue());
    case Instruction::Sub:
      return ConstantInt::get(ty, l->getSExtValue() - r->getSExtValue());
    case Instruction::Mul:
      return ConstantInt::get(ty, l->getSExtValue() * r->getSExtValue());
    case Instruction::SDiv:
      if (r->isZero())
        return nullptr;
      return ConstantInt::get(ty, l->getSExtValue() / r->getSExtValue());
    case Instruction::UDiv:
      if (r->isZero())
        return nullptr;
      return ConstantInt::get(
        ty,
        static_cast<int64_t>(l->getZExtValue() / r->getZExtValue()));
    case Instruction::SRem:
      if (r->isZero())
        return nullptr;
      return ConstantInt::get(ty, l->getSExtValue() % r->getSExtValue());
    case Instruction::URem:
      if (r->isZero())
        return nullptr;
      return ConstantInt::get(
        ty,
        static_cast<int64_t>(l->getZExtValue() % r->getZExtValue()));
    case Instruction::And:
      return ConstantInt::get(ty, l->getZExtValue() & r->getZExtValue());
    case Instruction::Or:
      return ConstantInt::get(ty, l->getZExtValue() | r->getZExtValue());
    case Instruction::Xor:
      return ConstantInt::get(ty, l->getZExtValue() ^ r->getZExtValue());
    case Instruction::Shl: {
      auto v = r->getZExtValue();
      if (v >= ty->getIntegerBitWidth())
        return nullptr;
      return ConstantInt::get(ty, l->getZExtValue() << v);
    }
    case Instruction::LShr: {
      auto v = r->getZExtValue();
      if (v >= ty->getIntegerBitWidth())
        return nullptr;
      return ConstantInt::get(
        ty, static_cast<int64_t>(l->getZExtValue() >> v));
    }
    case Instruction::AShr: {
      auto v = r->getZExtValue();
      if (v >= ty->getIntegerBitWidth())
        return nullptr;
      return ConstantInt::get(ty, l->getSExtValue() >> v);
    }
    default:
      return nullptr;
  }
}

Constant*
foldICmp(ICmpInst* cmp, ConstantInt* l, ConstantInt* r)
{
  bool res = false;
  switch (cmp->getPredicate()) {
    case ICmpInst::ICMP_EQ:
      res = l->getSExtValue() == r->getSExtValue();
      break;
    case ICmpInst::ICMP_NE:
      res = l->getSExtValue() != r->getSExtValue();
      break;
    case ICmpInst::ICMP_SLT:
      res = l->getSExtValue() < r->getSExtValue();
      break;
    case ICmpInst::ICMP_SLE:
      res = l->getSExtValue() <= r->getSExtValue();
      break;
    case ICmpInst::ICMP_SGT:
      res = l->getSExtValue() > r->getSExtValue();
      break;
    case ICmpInst::ICMP_SGE:
      res = l->getSExtValue() >= r->getSExtValue();
      break;
    case ICmpInst::ICMP_ULT:
      res = l->getZExtValue() < r->getZExtValue();
      break;
    case ICmpInst::ICMP_ULE:
      res = l->getZExtValue() <= r->getZExtValue();
      break;
    case ICmpInst::ICMP_UGT:
      res = l->getZExtValue() > r->getZExtValue();
      break;
    case ICmpInst::ICMP_UGE:
      res = l->getZExtValue() >= r->getZExtValue();
      break;
    default:
      return nullptr;
  }
  return ConstantInt::get(cmp->getType(), res ? 1 : 0);
}

// ---------------------------------------------------------------------------
// Algebraic simplification
// ---------------------------------------------------------------------------
Value*
simplifyBinop(BinaryOperator* bo)
{
  Value* L = bo->getOperand(0);
  Value* R = bo->getOperand(1);
  auto ty = bo->getType();
  auto* CL = dyn_cast<ConstantInt>(L);
  auto* CR = dyn_cast<ConstantInt>(R);

  if (CL && CR)
    return foldBinop(bo, CL, CR);

  switch (bo->getOpcode()) {
    case Instruction::Add:
      if (CR && CR->isZero())
        return L;
      if (CL && CL->isZero())
        return R;
      break;
    case Instruction::Sub:
      if (CR && CR->isZero())
        return L;
      if (L == R)
        return ConstantInt::get(ty, 0);
      break;
    case Instruction::Mul:
      if (CR && CR->isZero())
        return ConstantInt::get(ty, 0);
      if (CL && CL->isZero())
        return ConstantInt::get(ty, 0);
      if (CR && CR->getSExtValue() == 1)
        return L;
      if (CL && CL->getSExtValue() == 1)
        return R;
      break;
    case Instruction::SDiv:
    case Instruction::UDiv:
      if (CR && CR->getSExtValue() == 1)
        return L;
      if (CL && CL->isZero())
        return ConstantInt::get(ty, 0);
      break;
    case Instruction::SRem:
    case Instruction::URem:
      if (CR && CR->getSExtValue() == 1)
        return ConstantInt::get(ty, 0);
      if (CL && CL->isZero())
        return ConstantInt::get(ty, 0);
      break;
    case Instruction::And:
      if (CR && CR->isZero())
        return ConstantInt::get(ty, 0);
      if (CL && CL->isZero())
        return ConstantInt::get(ty, 0);
      if (CR && CR->isMinusOne())
        return L;
      if (CL && CL->isMinusOne())
        return R;
      if (L == R)
        return L;
      break;
    case Instruction::Or:
      if (CR && CR->isZero())
        return L;
      if (CL && CL->isZero())
        return R;
      if (CR && CR->isMinusOne())
        return CR;
      if (CL && CL->isMinusOne())
        return CL;
      if (L == R)
        return L;
      break;
    case Instruction::Xor:
      if (CR && CR->isZero())
        return L;
      if (CL && CL->isZero())
        return R;
      if (L == R)
        return ConstantInt::get(ty, 0);
      break;
    case Instruction::Shl:
    case Instruction::AShr:
    case Instruction::LShr:
      if (CR && CR->isZero())
        return L;
      if (CL && CL->isZero())
        return ConstantInt::get(ty, 0);
      break;
    default:
      break;
  }
  return nullptr;
}

// ---------------------------------------------------------------------------
// Re-associate `(x op c1) op c2` => `x op (c1 op c2)`
// ---------------------------------------------------------------------------
Value*
reassocBinop(BinaryOperator* bo)
{
  auto opc = bo->getOpcode();
  if (opc != Instruction::Add && opc != Instruction::Sub &&
      opc != Instruction::Mul)
    return nullptr;

  auto C2 = dyn_cast<ConstantInt>(bo->getOperand(1));
  if (!C2)
    return nullptr;
  auto inner = dyn_cast<BinaryOperator>(bo->getOperand(0));
  if (!inner || !inner->hasOneUse())
    return nullptr;

  auto innerOpc = inner->getOpcode();
  auto C1 = dyn_cast<ConstantInt>(inner->getOperand(1));
  if (!C1)
    return nullptr;

  IRBuilder<> b(bo);
  if (opc == Instruction::Add) {
    if (innerOpc == Instruction::Add) {
      auto v = C1->getSExtValue() + C2->getSExtValue();
      return b.CreateAdd(inner->getOperand(0),
                         ConstantInt::get(bo->getType(), v));
    }
    if (innerOpc == Instruction::Sub) {
      auto v = C2->getSExtValue() - C1->getSExtValue();
      return b.CreateAdd(inner->getOperand(0),
                         ConstantInt::get(bo->getType(), v));
    }
  }
  if (opc == Instruction::Sub) {
    if (innerOpc == Instruction::Add) {
      auto v = C1->getSExtValue() - C2->getSExtValue();
      return b.CreateAdd(inner->getOperand(0),
                         ConstantInt::get(bo->getType(), v));
    }
    if (innerOpc == Instruction::Sub) {
      auto v = C1->getSExtValue() + C2->getSExtValue();
      return b.CreateSub(inner->getOperand(0),
                         ConstantInt::get(bo->getType(), v));
    }
  }
  if (opc == Instruction::Mul && innerOpc == Instruction::Mul) {
    auto v = C1->getSExtValue() * C2->getSExtValue();
    return b.CreateMul(inner->getOperand(0),
                       ConstantInt::get(bo->getType(), v));
  }
  return nullptr;
}

// ---------------------------------------------------------------------------
// CSE
// ---------------------------------------------------------------------------
struct InstKey
{
  unsigned opc;
  Type* ty;
  std::vector<Value*> ops;
  unsigned subop = 0;
  bool operator==(const InstKey& other) const
  {
    return opc == other.opc && ty == other.ty && subop == other.subop &&
           ops == other.ops;
  }
};

struct InstKeyHash
{
  size_t operator()(const InstKey& k) const
  {
    size_t h = std::hash<unsigned>()(k.opc) ^ std::hash<void*>()(k.ty) ^
               std::hash<unsigned>()(k.subop);
    for (auto v : k.ops)
      h = h * 1315423911u + std::hash<void*>()(v);
    return h;
  }
};

bool
isCSEable(Instruction& I)
{
  if (I.mayHaveSideEffects() || I.mayReadFromMemory())
    return false;
  if (isa<PHINode>(I) || isa<AllocaInst>(I) || isa<LandingPadInst>(I))
    return false;
  if (I.isTerminator())
    return false;
  if (isa<CallBase>(I))
    return false;
  if (I.getType()->isVoidTy())
    return false;
  return true;
}

InstKey
keyOf(Instruction& I)
{
  InstKey k;
  k.opc = I.getOpcode();
  k.ty = I.getType();
  for (Value* v : I.operands())
    k.ops.push_back(v);
  if (auto cmp = dyn_cast<ICmpInst>(&I))
    k.subop = cmp->getPredicate();
  if (I.isCommutative() && k.ops.size() == 2) {
    if (k.ops[0] > k.ops[1])
      std::swap(k.ops[0], k.ops[1]);
  }
  return k;
}

// ---------------------------------------------------------------------------
// Load forwarding inside a single BB
// ---------------------------------------------------------------------------
Value*
forwardLoad(LoadInst* li)
{
  auto ptr = li->getPointerOperand();
  auto ty = li->getType();
  auto* bb = li->getParent();
  for (auto it = li->getIterator(); it != bb->begin();) {
    --it;
    Instruction* prev = &*it;
    if (auto si = dyn_cast<StoreInst>(prev)) {
      if (si->getPointerOperand() == ptr &&
          si->getValueOperand()->getType() == ty)
        return si->getValueOperand();
      return nullptr;
    }
    if (auto pl = dyn_cast<LoadInst>(prev)) {
      if (pl->getPointerOperand() == ptr && pl->getType() == ty)
        return pl;
      continue;
    }
    if (isa<CallBase>(prev))
      return nullptr;
  }
  return nullptr;
}

// Eliminate redundant stores in the same BB:
//   store v, p ; (no read/call to p) ; store w, p  →  drop the first.
bool
isStoreDead(StoreInst* si)
{
  auto ptr = si->getPointerOperand();
  auto bb = si->getParent();
  auto it = si->getIterator();
  for (++it; it != bb->end(); ++it) {
    Instruction* nxt = &*it;
    if (auto ns = dyn_cast<StoreInst>(nxt)) {
      if (ns->getPointerOperand() == ptr)
        return true;
      return false;
    }
    if (auto nl = dyn_cast<LoadInst>(nxt)) {
      if (nl->getPointerOperand() == ptr)
        return false;
      continue;
    }
    if (isa<CallBase>(nxt))
      return false;
  }
  return false;
}

// ---------------------------------------------------------------------------
// Collapse a chain of `add x, y` (or `add y, x`) accumulating the same value
// `v` many times, into a single `add base, (mul v, N)`.
// ---------------------------------------------------------------------------
Value*
collapseAddChain(BinaryOperator* tail)
{
  if (tail->getOpcode() != Instruction::Add)
    return nullptr;

  // Try both possible "constant operand" choices.
  for (int which = 0; which < 2; ++which) {
    Value* v = tail->getOperand(which);
    Value* cur = tail->getOperand(1 - which);
    unsigned count = 1;
    // Walk while `cur` is `add v, ?` or `add ?, v` and single-use.
    while (true) {
      auto inner = dyn_cast<BinaryOperator>(cur);
      if (!inner || inner->getOpcode() != Instruction::Add)
        break;
      if (!inner->hasOneUse())
        break;
      Value* iL = inner->getOperand(0);
      Value* iR = inner->getOperand(1);
      Value* next = nullptr;
      if (iL == v)
        next = iR;
      else if (iR == v)
        next = iL;
      else
        break;
      ++count;
      cur = next;
    }
    if (count < 3)
      continue;
    IRBuilder<> b(tail);
    auto N = ConstantInt::get(tail->getType(), count);
    auto mul = b.CreateMul(v, N);
    auto sum = b.CreateAdd(cur, mul);
    return sum;
  }
  return nullptr;
}

// ---------------------------------------------------------------------------
// Strength reduction: `sdiv x, 2^n`  →  `(x + ((x >> 31) >> (32-n))) >> n`
// Specifically for sdiv by 2: `(x + lshr(x,31)) >> 1`.
// ---------------------------------------------------------------------------
Value*
strengthReduceSDiv(BinaryOperator* bo)
{
  if (bo->getOpcode() != Instruction::SDiv)
    return nullptr;
  auto cr = dyn_cast<ConstantInt>(bo->getOperand(1));
  if (!cr)
    return nullptr;
  int64_t v = cr->getSExtValue();
  if (v <= 0 || (v & (v - 1)) != 0)
    return nullptr; // not a positive power of two
  unsigned n = llvm::Log2_64(v);
  auto ty = bo->getType();
  unsigned bw = ty->getIntegerBitWidth();
  IRBuilder<> b(bo);
  Value* x = bo->getOperand(0);
  // sign := lshr x, (bw-1)        — 1 if negative else 0
  Value* sign = b.CreateLShr(x, ConstantInt::get(ty, bw - 1));
  Value* offset;
  if (n == 1) {
    offset = sign;
  } else {
    // For larger n: ashr to fill with sign, then lshr to take low n bits.
    // Equivalent: round-toward-zero adjustment = sign * ((1<<n) - 1)
    Value* mask = ConstantInt::get(ty, (1LL << n) - 1);
    Value* signFull = b.CreateAShr(x, ConstantInt::get(ty, bw - 1));
    offset = b.CreateAnd(signFull, mask);
    (void)sign; // unused
  }
  Value* adj = b.CreateAdd(x, offset);
  return b.CreateAShr(adj, ConstantInt::get(ty, n));
}

// ---------------------------------------------------------------------------
//
// For each loop in the function, hoist every instruction whose operands are
// all defined outside the loop AND that is "safe to speculate".  We pick the
// loop preheader (creating one if necessary) as the destination.  We also
// hoist loads of pointers that are not written to inside the loop.
// ---------------------------------------------------------------------------
bool
isSafeToHoist(Instruction& I)
{
  if (I.mayHaveSideEffects())
    return false;
  if (isa<PHINode>(I))
    return false;
  if (isa<AllocaInst>(I))
    return false;
  if (I.isTerminator())
    return false;
  if (isa<CallBase>(I))
    return false;
  if (I.getType()->isVoidTy())
    return false;
  // Be conservative with division/modulo: may trap on /0.
  if (auto bo = dyn_cast<BinaryOperator>(&I)) {
    switch (bo->getOpcode()) {
      case Instruction::SDiv:
      case Instruction::UDiv:
      case Instruction::SRem:
      case Instruction::URem:
        // Only hoist if divisor is a non-zero constant.
        if (auto ci = dyn_cast<ConstantInt>(bo->getOperand(1))) {
          if (ci->isZero())
            return false;
        } else {
          return false;
        }
        break;
      default:
        break;
    }
  }
  return true;
}

// Returns true iff `V` is loop-invariant relative to `L`.
bool
isLoopInvariantValue(Value* V, Loop* L)
{
  auto I = dyn_cast<Instruction>(V);
  if (!I)
    return true;
  return !L->contains(I->getParent());
}

// Returns true if `L` writes (other than the given `excluded` store) to `ptr`
// or contains any call (which we treat as a barrier).
bool
loopWritesToPtr(Loop* L, Value* ptr, StoreInst* excluded = nullptr)
{
  for (auto* bb : L->blocks()) {
    for (auto& I : *bb) {
      if (auto si = dyn_cast<StoreInst>(&I)) {
        if (si == excluded)
          continue;
        // Conservative: any other store may alias with our ptr.
        return true;
      }
      if (isa<CallBase>(I))
        return true;
    }
  }
  return false;
}

bool
licmOnLoop(Loop* L, DominatorTree& DT, LoopInfo& LI)
{
  bool changed = false;

  // Build preheader if needed.  We create one only if there's exactly one
  // "outside" predecessor of the header.
  auto header = L->getHeader();
  BasicBlock* preheader = L->getLoopPreheader();
  if (!preheader)
    return false; // skip irregular loops

  // Recurse into subloops first.
  for (auto sub : L->getSubLoops())
    changed |= licmOnLoop(sub, DT, LI);

  std::vector<Instruction*> toHoist;
  for (auto* bb : L->blocks()) {
    // Skip subloops to avoid double-hoisting (only consider blocks directly
    // owned by this loop).
    if (LI.getLoopFor(bb) != L)
      continue;
    for (auto& I : *bb) {
      if (!isSafeToHoist(I))
        continue;
      // Loads: only if no store inside the loop writes their ptr.
      if (auto li = dyn_cast<LoadInst>(&I)) {
        if (!isLoopInvariantValue(li->getPointerOperand(), L))
          continue;
        if (loopWritesToPtr(L, li->getPointerOperand()))
          continue;
        toHoist.push_back(&I);
        continue;
      }
      // Other safe insts: all operands invariant?
      bool ok = true;
      for (Value* op : I.operands()) {
        if (!isLoopInvariantValue(op, L)) {
          ok = false;
          break;
        }
      }
      if (ok)
        toHoist.push_back(&I);
    }
  }

  // Hoist them in order (so dependencies are satisfied).
  auto insertPt = preheader->getTerminator();
  for (auto* I : toHoist) {
    I->moveBefore(insertPt);
    changed = true;
  }
  return changed;
}

bool
runLICM(Function& F)
{
  if (F.isDeclaration())
    return false;

  // Compute fresh DominatorTree and LoopInfo.
  DominatorTree DT(F);
  LoopInfo LI(DT);

  bool changed = false;
  for (auto L : LI)
    changed |= licmOnLoop(L, DT, LI);
  return changed;
}

// ---------------------------------------------------------------------------
bool
mergeWithSingleSuccessor(BasicBlock& BB)
{
  auto term = BB.getTerminator();
  auto br = dyn_cast<BranchInst>(term);
  if (!br || !br->isUnconditional())
    return false;
  auto succ = br->getSuccessor(0);
  if (succ == &BB)
    return false;
  if (succ->getSinglePredecessor() != &BB)
    return false;
  // Don't merge entry block away.
  if (succ == &succ->getParent()->getEntryBlock())
    return false;

  // Replace any PHI nodes in succ with their incoming value from BB.
  while (auto phi = dyn_cast<PHINode>(&succ->front())) {
    Value* v = phi->getIncomingValueForBlock(&BB);
    phi->replaceAllUsesWith(v);
    phi->eraseFromParent();
  }

  br->eraseFromParent();
  // Move all instructions from succ into BB at the end.
  BB.splice(BB.end(), succ);
  // Update PHIs in successors of succ to refer to BB instead.
  succ->replaceAllUsesWith(&BB);
  succ->eraseFromParent();
  return true;
}

// ---------------------------------------------------------------------------
// Fixed-point driver
// ---------------------------------------------------------------------------
bool
runOnFunction(Function& F)
{
  if (F.isDeclaration())
    return false;

  bool changedAny = false;

  // Outer fixed-point: simplification → LICM → repeat.
  bool outerChanged = true;
  int outerIter = 0;
  while (outerChanged && outerIter++ < 8) {
    outerChanged = false;

    if (runLICM(F)) {
      outerChanged = true;
      changedAny = true;
    }

    bool changed = true;
    int iter = 0;
    const int kMaxIter = 50;

    while (changed && iter++ < kMaxIter) {
      changed = false;

    // Pass 1: per-instruction simplification.
    for (auto& bb : F) {
      for (auto it = bb.begin(); it != bb.end();) {
        Instruction* I = &*it;
        ++it;

        if (auto li = dyn_cast<LoadInst>(I)) {
          if (auto repl = forwardLoad(li)) {
            li->replaceAllUsesWith(repl);
            li->eraseFromParent();
            changed = true;
            continue;
          }
        }

        if (auto bo = dyn_cast<BinaryOperator>(I)) {
          if (auto repl = simplifyBinop(bo)) {
            bo->replaceAllUsesWith(repl);
            bo->eraseFromParent();
            changed = true;
            continue;
          }
          if (auto repl = reassocBinop(bo)) {
            bo->replaceAllUsesWith(repl);
            bo->eraseFromParent();
            changed = true;
            continue;
          }
          if (auto repl = collapseAddChain(bo)) {
            bo->replaceAllUsesWith(repl);
            bo->eraseFromParent();
            changed = true;
            continue;
          }
        }

        if (auto cmp = dyn_cast<ICmpInst>(I)) {
          auto* CL = dyn_cast<ConstantInt>(cmp->getOperand(0));
          auto* CR = dyn_cast<ConstantInt>(cmp->getOperand(1));
          if (CL && CR) {
            if (auto repl = foldICmp(cmp, CL, CR)) {
              cmp->replaceAllUsesWith(repl);
              cmp->eraseFromParent();
              changed = true;
              continue;
            }
          }
          if (cmp->getOperand(0) == cmp->getOperand(1)) {
            bool eq = cmp->getPredicate() == ICmpInst::ICMP_EQ ||
                      cmp->getPredicate() == ICmpInst::ICMP_SLE ||
                      cmp->getPredicate() == ICmpInst::ICMP_SGE ||
                      cmp->getPredicate() == ICmpInst::ICMP_ULE ||
                      cmp->getPredicate() == ICmpInst::ICMP_UGE;
            cmp->replaceAllUsesWith(ConstantInt::get(cmp->getType(), eq ? 1 : 0));
            cmp->eraseFromParent();
            changed = true;
            continue;
          }
        }

        // br i1 const  →  br label
        if (auto br = dyn_cast<BranchInst>(I)) {
          if (br->isConditional()) {
            if (auto cc = dyn_cast<ConstantInt>(br->getCondition())) {
              auto destTrue = br->getSuccessor(0);
              auto destFalse = br->getSuccessor(1);
              auto keep = cc->isZero() ? destFalse : destTrue;
              auto drop = cc->isZero() ? destTrue : destFalse;
              IRBuilder<> b(br);
              b.CreateBr(keep);
              if (drop != keep)
                drop->removePredecessor(br->getParent());
              br->eraseFromParent();
              changed = true;
              continue;
            }
          }
        }

        // PHI with all incoming values equal: replace.
        if (auto phi = dyn_cast<PHINode>(I)) {
          Value* common = nullptr;
          bool allSame = true;
          for (Value* iv : phi->incoming_values()) {
            if (iv == phi)
              continue;
            if (!common) {
              common = iv;
              continue;
            }
            if (iv != common) {
              allSame = false;
              break;
            }
          }
          if (allSame && common) {
            phi->replaceAllUsesWith(common);
            phi->eraseFromParent();
            changed = true;
            continue;
          }
        }
      }
    }

    // Pass 2: CSE within each BB.
    for (auto& bb : F) {
      std::unordered_map<InstKey, Value*, InstKeyHash> known;
      for (auto it = bb.begin(); it != bb.end();) {
        Instruction* I = &*it;
        ++it;
        if (!isCSEable(*I))
          continue;
        auto key = keyOf(*I);
        auto found = known.find(key);
        if (found != known.end()) {
          I->replaceAllUsesWith(found->second);
          I->eraseFromParent();
          changed = true;
        } else {
          known[key] = I;
        }
      }
    }

    // Pass 3: dead store elimination.
    for (auto& bb : F) {
      for (auto it = bb.begin(); it != bb.end();) {
        Instruction* I = &*it;
        ++it;
        if (auto si = dyn_cast<StoreInst>(I)) {
          if (isStoreDead(si)) {
            si->eraseFromParent();
            changed = true;
          }
        }
      }
    }

    // Pass 4: dead code elimination (instructions with no users).
    for (auto& bb : F) {
      for (auto it = bb.rbegin(); it != bb.rend();) {
        Instruction* I = &*it;
        ++it;
        if (I->use_empty() && isDeadIfUnused(*I)) {
          I->eraseFromParent();
          changed = true;
        }
      }
    }

    // Pass 5: block merging via LLVM's utility helper.
    {
      bool mergedSomething = true;
      while (mergedSomething) {
        mergedSomething = false;
        for (auto it = F.begin(); it != F.end();) {
          BasicBlock& bb = *it;
          ++it;
          // Skip the entry block — MergeBlockIntoPredecessor refuses anyway.
          if (&bb == &F.getEntryBlock())
            continue;
          if (llvm::MergeBlockIntoPredecessor(&bb)) {
            mergedSomething = true;
            changed = true;
            break;
          }
        }
      }
    }

    if (changed)
      changedAny = true;
    if (changed)
      outerChanged = true;
    } // inner while
  } // outer while

  // Apply strength reduction once at the end (don't iterate to avoid
  // re-lowering already-lowered patterns).
  for (auto& bb : F) {
    for (auto it = bb.begin(); it != bb.end();) {
      Instruction* I = &*it;
      ++it;
      if (auto bo = dyn_cast<BinaryOperator>(I)) {
        if (auto repl = strengthReduceSDiv(bo)) {
          bo->replaceAllUsesWith(repl);
          bo->eraseFromParent();
          changedAny = true;
        }
      }
    }
  }

  return changedAny;
}

} // namespace

namespace {

// Heuristic: count instructions in F (estimate of inlining cost).
unsigned
instrCount(const Function& F)
{
  unsigned n = 0;
  for (auto& bb : F)
    n += bb.size();
  return n;
}

// Return true iff `F` contains a call to `target`.
bool
calls(Function& F, Function* target)
{
  for (auto& bb : F)
    for (auto& I : bb)
      if (auto cb = dyn_cast<CallBase>(&I))
        if (cb->getCalledFunction() == target)
          return true;
  return false;
}

// Inline every call to small, non-recursive, defined-in-module functions.
// Returns true on change.
bool
runInlining(Module& mod)
{
  bool changed = true;
  bool any = false;
  int iter = 0;
  while (changed && iter++ < 4) {
    changed = false;

    // Snapshot all call sites worth inlining.
    std::vector<CallBase*> callsites;
    for (auto& F : mod) {
      for (auto& bb : F) {
        for (auto& I : bb) {
          auto cb = dyn_cast<CallBase>(&I);
          if (!cb)
            continue;
          auto callee = cb->getCalledFunction();
          if (!callee)
            continue;
          if (callee->isDeclaration())
            continue;
          if (callee == &F)
            continue; // skip direct recursion
          // Skip if callee calls itself (recursive).  Conservative.
          if (calls(*callee, callee))
            continue;
          // Inline only "small" functions.
          if (instrCount(*callee) > 2000)
            continue;
          callsites.push_back(cb);
        }
      }
    }

    for (auto* cb : callsites) {
      InlineFunctionInfo IFI;
      auto res = InlineFunction(*cb, IFI);
      if (res.isSuccess()) {
        changed = true;
        any = true;
      }
    }
  }
  return any;
}

} // namespace

PreservedAnalyses
Simplify::run(Module& mod, ModuleAnalysisManager& mam)
{
  bool any = false;

  // First inline small non-recursive functions; this exposes more
  // opportunities for the per-function simplifier.
  any |= runInlining(mod);

  for (auto& F : mod)
    any |= runOnFunction(F);

  // Second inlining pass (functions are smaller after optimization).
  any |= runInlining(mod);
  for (auto& F : mod)
    any |= runOnFunction(F);

  if (!any)
    return PreservedAnalyses::all();
  return PreservedAnalyses::none();
}

